    frames[i] = Math.sin(phase * Math.PI * 2.0) * gain
    const t = i / numberOfFrames
    const freq = f0 * Math.pow(f1 / f0, 1.0 - Math.abs(2.0 * t - 1.0)) // up and down chirp
