const tapeUnit = project.addInstrumentUnit("Tape")
const audioTrack = tapeUnit.addAudioTrack()
audioTrack.addRegion(sample, {playback: AudioPlayback.NoWarp, duration: numberOfFrames / sampleRate})
project.openInStudio()
